const Font_t UIFont_LabelAA = {
  14U,
  14U,
  (uint8_t)(sizeof(LabelGlyphs) / sizeof(LabelGlyphs[0])),
  LabelGlyphs
};

static const Font_t *UIFont_SelectNumericFont(uint8_t scale)
{
  if (scale >= 4U)
  {
    return &UIFont_LargeNumericAA;
  }

  if (scale >= 3U)
  {
    return &UIFont_MediumNumericAA;
  }

  if (scale >= 2U)
  {
    return &UIFont_SmallNumericAA;
  }

  return &UIFont_LabelAA;
}

uint16_t UIFont_BlendRGB565(uint16_t foreground, uint16_t background, uint8_t alpha)
{
  uint16_t inverse_alpha;
  uint16_t foreground_red;
  uint16_t foreground_green;
  uint16_t foreground_blue;
  uint16_t background_red;
  uint16_t background_green;
  uint16_t background_blue;
  uint16_t red;
  uint16_t green;
  uint16_t blue;

  if (alpha == 0U)
  {
    return background;
  }

  if (alpha == 255U)
  {
    return foreground;
  }

  inverse_alpha = (uint16_t)(255U - alpha);
  foreground_red = (uint16_t)((((foreground >> 11) & 0x1FU) * 255U) / 31U);
  foreground_green = (uint16_t)((((foreground >> 5) & 0x3FU) * 255U) / 63U);
  foreground_blue = (uint16_t)(((foreground & 0x1FU) * 255U) / 31U);
  background_red = (uint16_t)((((background >> 11) & 0x1FU) * 255U) / 31U);
  background_green = (uint16_t)((((background >> 5) & 0x3FU) * 255U) / 63U);
  background_blue = (uint16_t)(((background & 0x1FU) * 255U) / 31U);
  red = (uint16_t)(((foreground_red * alpha) + (background_red * inverse_alpha) + 127U) / 255U);
  green = (uint16_t)(((foreground_green * alpha) + (background_green * inverse_alpha) + 127U) / 255U);
  blue = (uint16_t)(((foreground_blue * alpha) + (background_blue * inverse_alpha) + 127U) / 255U);

  return ILI9341_RGB565(red, green, blue);
}

const FontGlyph_t *UIFont_FindGlyph(const Font_t *font, char ch)
{
  if ((font == 0) || (font->glyphs == 0))
  {
    return 0;
  }

  for (uint8_t i = 0U; i < font->glyph_count; i++)
  {
    if (font->glyphs[i].code == ch)
    {
      return &font->glyphs[i];
    }
  }

  return 0;
}

uint8_t UIFont_FontCanDraw(const Font_t *font, const char *text)
{
  if ((font == 0) || (text == 0))
  {
    return 0U;
  }

  while (*text != '\0')
  {
    if (UIFont_FindGlyph(font, *text) == 0)
    {
      return 0U;
    }

    text++;
  }

  return 1U;
}

uint16_t UIFont_GetStringWidthAA(const Font_t *font, const char *text)
{
  uint16_t width = 0U;

  if ((font == 0) || (text == 0))
  {
    return 0U;
  }

  while (*text != '\0')
  {
    const FontGlyph_t *glyph = UIFont_FindGlyph(font, *text);

    if (glyph == 0)
    {
      return 0U;
    }

    width = (uint16_t)(width + glyph->x_advance);
    text++;
  }

  return width;
}

uint16_t UIFont_GetStringHeightAA(const Font_t *font)
{
  return (font != 0) ? font->line_height : 0U;
}

void UIFont_DrawGlyphAA(uint16_t x, uint16_t y, const Font_t *font, const FontGlyph_t *glyph, uint16_t foreground, uint16_t background)
{
  uint16_t draw_x;
  uint16_t draw_y;
  uint32_t index = 0U;

  (void)font;

  if ((glyph == 0) || (glyph->coverage == 0) || (glyph->width == 0U) || (glyph->height == 0U))
  {
    return;
  }

  draw_x = (uint16_t)(x + glyph->x_offset);
  draw_y = (uint16_t)(y + glyph->y_offset);

  for (uint8_t row = 0U; row < glyph->height; row++)
  {
    for (uint8_t column = 0U; column < glyph->width; column++)
    {
      uint8_t alpha = glyph->coverage[index];

      if (alpha != 0U)
      {
        ILI9341_DrawPixel((uint16_t)(draw_x + column),
                          (uint16_t)(draw_y + row),
                          UIFont_BlendRGB565(foreground, background, alpha));
      }

      index++;
    }
  }
}

void UIFont_DrawStringAA(uint16_t x, uint16_t y, const Font_t *font, const char *text, uint16_t foreground, uint16_t background)
{
  uint16_t cursor_x = x;

  if ((font == 0) || (text == 0))
  {
    return;
  }

  while (*text != '\0')
  {
    const FontGlyph_t *glyph = UIFont_FindGlyph(font, *text);

    if (glyph == 0)
    {
      return;
    }

    UIFont_DrawGlyphAA(cursor_x, y, font, glyph, foreground, background);
    cursor_x = (uint16_t)(cursor_x + glyph->x_advance);
    text++;
  }
}

uint8_t UIFont_IsNumericText(const char *text)
{
  uint8_t has_visible_char = 0U;

  if (text == 0)
  {
    return 0U;
  }

  while (*text != '\0')
  {
    if (((*text < '0') || (*text > '9')) &&
        (*text != '.') &&
        (*text != ':') &&
        (*text != '-') &&
        (*text != ' '))
    {
      return 0U;
    }

    if (*text != ' ')
    {
      has_visible_char = 1U;
    }

    text++;
  }

  return has_visible_char;
}

uint16_t UIFont_GetNumericTextWidth(const char *text, uint8_t scale)
{
  return UIFont_GetStringWidthAA(UIFont_SelectNumericFont(scale), text);
}

uint16_t UIFont_GetNumericTextHeight(uint8_t scale)
{
  return UIFont_GetStringHeightAA(UIFont_SelectNumericFont(scale));
}

void UIFont_DrawNumericString(uint16_t x, uint16_t y, const char *text, uint16_t color, uint16_t background, uint8_t scale)
{
  const Font_t *font = UIFont_SelectNumericFont(scale);
  uint8_t fallback_size = scale;

  if (UIFont_FontCanDraw(font, text) != 0U)
  {
    UIFont_DrawStringAA(x, y, font, text, color, background);
    return;
  }

  if (fallback_size == 0U)
  {
    fallback_size = 1U;
  }

  if (fallback_size > 3U)
  {
    fallback_size = 3U;
  }

  ILI9341_DrawString(x, y, text, color, background, fallback_size);
}

void UIFont_DrawBoldString(uint16_t x, uint16_t y, const char *text, uint16_t color, uint16_t background, uint8_t size)
{
  if ((text == 0) || (size == 0U))
  {
    return;
  }

  if (UIFont_FontCanDraw(&UIFont_LabelAA, text) != 0U)
  {
    UIFont_DrawStringAA(x, y, &UIFont_LabelAA, text, color, background);
    return;
  }

  ILI9341_DrawString(x, y, text, color, background, size);
}
